  1	import React, { FC, useMemo, useState } from 'react';
  2	
  3	import { IoK8sApiCoreV1PersistentVolumeClaim } from '@kubevirt-ui/kubevirt-api/kubernetes';
  4	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
  5	import Loading from '@kubevirt-utils/components/Loading/Loading';
  6	import StateHandler from '@kubevirt-utils/components/StateHandler/StateHandler';
  7	import useDefaultStorageClass from '@kubevirt-utils/hooks/useDefaultStorage/useDefaultStorageClass';
  8	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  9	import { getName } from '@kubevirt-utils/resources/shared';
 10	import useDisksSources from '@kubevirt-utils/resources/vm/hooks/disk/useDisksSources';
 11	import { isEmpty } from '@kubevirt-utils/utils/utils';
 12	import { Modal, Wizard, WizardHeader, WizardStep } from '@patternfly/react-core';
 13	
 14	import VirtualMachineMigrationDestinationTab from './tabs/VirtualMachineMigrationDestinationTab';
 15	import VirtualMachineMigrationDetails from './tabs/VirtualMachineMigrationDetails';
 16	import VirtualMachineMigrationReviewTab from './tabs/VirtualMachineMigrationReviewTab';
 17	import { entireVMSelected, getMigratableVMPVCs, migrateVM } from './utils';
 18	import VirtualMachineMigrationStatus from './VirtualMachineMigrationStatus';
 19	
 20	import './virtual-machine-migration-modal.scss';
 21	
 22	export type VirtualMachineMigrateModalProps = {
 23	  isOpen: boolean;
 24	  onClose: () => Promise<void> | void;
 25	  vm: V1VirtualMachine;
 26	};
 27	
 28	const VirtualMachineMigrateModal: FC<VirtualMachineMigrateModalProps> = ({
 29	  isOpen,
 30	  onClose,
 31	  vm,
 32	}) => {
 33	  const { t } = useKubevirtTranslation();
 34	
 35	  const [selectedStorageClass, setSelectedStorageClass] = useState('');
 36	  const [migrationError, setMigrationError] = useState<Error | null>(null);
 37	  const [migrationLoading, setMigrationLoading] = useState(false);
 38	  const [migrationStarted, setMigrationStarted] = useState(false);
 39	
 40	  const [selectedPVCs, setSelectedPVCs] = useState<IoK8sApiCoreV1PersistentVolumeClaim[] | null>(
 41	    null,
 42	  );
 43	
 44	  const { loaded, loadingError, pvcs } = useDisksSources(vm);
 45	
 46	  const [{ clusterDefaultStorageClass, sortedStorageClasses }, scLoaded] = useDefaultStorageClass();
 47	
 48	  const pvcsToMigrate = entireVMSelected(selectedPVCs)
 49	    ? getMigratableVMPVCs(vm, pvcs)
 50	    : selectedPVCs;
 51	
 52	  const defaultStorageClassName = useMemo(
 53	    () => getName(clusterDefaultStorageClass),
 54	    [clusterDefaultStorageClass],
 55	  );
 56	
 57	  const destinationStorageClass = useMemo(
 58	    () => selectedStorageClass || defaultStorageClassName,
 59	    [defaultStorageClassName, selectedStorageClass],
 60	  );
 61	
 62	  const onSubmit = async () => {
 63	    setMigrationLoading(true);
 64	    setMigrationError(null);
 65	    try {
 66	      await migrateVM(vm, pvcsToMigrate, destinationStorageClass);
 67	
 68	      setMigrationStarted(true);
 69	    } catch (apiError) {
 70	      setMigrationError(apiError);
 71	    }
 72	
 73	    setMigrationLoading(false);
 74	  };
 75	
 76	  const nothingSelected = !entireVMSelected(selectedPVCs) && isEmpty(selectedPVCs);
 77	
 78	  return (
 79	    <Modal
 80	      className="virtual-machine-migration-modal"
 81	      id="virtual-machine-migration-modal"
 82	      isOpen={isOpen}
 83	      showClose={false}
 84	      variant="large"
 85	    >
 86	      <StateHandler error={loadingError} loaded>
 87	        {migrationStarted ? (
 88	          <VirtualMachineMigrationStatus onClose={onClose} vm={vm} />
 89	        ) : (
 90	          <Wizard
 91	            header={
 92	              <WizardHeader
 93	                closeButtonAriaLabel={t('Close header')}
 94	                description={t('Migrate VirtualMachine storage to a different StorageClass.')}
 95	                onClose={onClose}
 96	                title={t('Migrate VirtualMachine storage')}
 97	              />
 98	            }
 99	            onClose={onClose}
100	            onSave={onSubmit}
101	            title={t('Migrate VirtualMachine storage')}
102	          >
103	            <WizardStep
104	              footer={{ isNextDisabled: nothingSelected }}
105	              id="wizard-migration-details"
106	              name={t('Migration details')}
107	            >
108	              {loaded && scLoaded ? (
109	                <VirtualMachineMigrationDetails
110	                  pvcs={pvcs}
111	                  selectedPVCs={selectedPVCs}
112	                  setSelectedPVCs={setSelectedPVCs}
113	                  vm={vm}
114	                />
115	              ) : (
116	                <Loading />
117	              )}
118	            </WizardStep>
119	            <WizardStep id="wizard-migrate-destination" name={t('Destination StorageClass')}>
120	              <VirtualMachineMigrationDestinationTab
121	                defaultStorageClassName={defaultStorageClassName}
122	                destinationStorageClass={destinationStorageClass}
123	                setSelectedStorageClass={setSelectedStorageClass}
124	                sortedStorageClasses={sortedStorageClasses}
125	              />
126	            </WizardStep>
127	            <WizardStep
128	              footer={{
129	                isNextDisabled: migrationLoading,
130	                nextButtonText: t('Migrate VirtualMachine storage'),
131	              }}
132	              id="wizard-migrate-review"
133	              name={t('Review')}
134	            >
135	              <VirtualMachineMigrationReviewTab
136	                defaultStorageClassName={defaultStorageClassName}
137	                destinationStorageClass={destinationStorageClass}
138	                migrationError={migrationError}
139	                pvcs={pvcsToMigrate}
140	                vm={vm}
141	              />
142	            </WizardStep>
143	          </Wizard>
144	        )}
145	      </StateHandler>
146	    </Modal>
147	  );
148	};
149	
150	export default VirtualMachineMigrateModal;

